package kr.gampa.battlegrounds.combat; import java.util.*; public final class ShotPattern{private ShotPattern(){}public static List<ShotOffset> create(int pellets,double spread,long seed){if(pellets<=0||spread<0)throw new IllegalArgumentException();Random r=new Random(seed);List<ShotOffset> out=new ArrayList<>(pellets);for(int i=0;i<pellets;i++)out.add(new ShotOffset((r.nextDouble()*2-1)*spread,(r.nextDouble()*2-1)*spread));return List.copyOf(out);}}